class Solution:
    def minAnagramLength(self, s: str) -> int:
        n = len(s)
        # Count total frequencies of each character in s
        total_counts = [0] * 26
        for char in s:
            total_counts[ord(char) - 97] += 1

        # Find all divisors of n
        divisors = []
        for i in range(1, int(n**0.5) + 1):
            if n % i == 0:
                divisors.append(i)
                if i * i != n:
                    divisors.append(n // i)
        divisors.sort()

        # Check each divisor L (length of t) in ascending order
        for L in divisors:
            k = n // L  # Number of blocks

            # Optimization: Check if total counts are divisible by k
            # This is a necessary condition for s to be formed by k anagrams of t
            possible = True
            for count in total_counts:
                if count % k != 0:
                    possible = False
                    break
            if not possible:
                continue

            # If counts are divisible, verify if blocks are actually anagrams
            # Compute target counts from the first block
            target = [0] * 26
            for char in s[:L]:
                target[ord(char) - 97] += 1

            # Check subsequent blocks
            is_valid = True
            for i in range(1, k):
                start = i * L
                end = start + L
                current = [0] * 26
                for char in s[start:end]:
                    current[ord(char) - 97] += 1
                if current != target:
                    is_valid = False
                    break

            if is_valid:
                return L

        return n
