    def maxTotalReward(self, rewardValues: List[int]) -> int:
        # Sort the reward values to process them in increasing order
        rewardValues.sort()

        # Use a set to keep track of reachable sums.
        # Initially, we have a sum of 0.
        reachable_sums = {0}

        # Iterate through each reward value
        for val in rewardValues:
            # We can only pick 'val' if it is strictly greater than the current sum.
            # If we pick 'val', the new sum will be current_sum + val.
            # We need to check if 'val' > current_sum for each reachable_sum.
            # To avoid modifying the set while iterating, we collect new sums first.
            new_sums = []
            for s in reachable_sums:
                if val > s:
                    new_sums.append(s + val)

            # Add the new reachable sums to the set
            for s in new_sums:
                reachable_sums.add(s)

        # The answer is the maximum sum reachable
        return max(reachable_sums)
