    def minimumArea(self, grid: List[List[int]]) -> int:
        min_r = float('inf')
        max_r = -1
        min_c = float('inf')
        max_c = -1

        for r, row in enumerate(grid):
            if 1 in row:
                if r < min_r:
                    min_r = r
                max_r = r

                # Find the first occurrence of 1 in the row
                first_c = row.index(1)
                if first_c < min_c:
                    min_c = first_c

                # Find the last occurrence of 1 in the row
                # row[::-1] creates a reversed copy, index(1) finds the first 1 in reversed list
                # which corresponds to the last 1 in the original list.
                last_c = len(row) - 1 - row[::-1].index(1)
                if last_c > max_c:
                    max_c = last_c

        return (max_r - min_r + 1) * (max_c - min_c + 1)
